// 1. Əsas tiplər
let userName: string = "Murad"; // Yalnız sətir
let userAge: number = 23; // Yalnız rəqəm
let isActive: boolean = true; // Yalnız true/false
// userName = 23; // Xəta: number string tipinə uyğun deyil

// 2. Tuple type: Sabit uzunluqlu siyahı
type UserInfo = [string, number];
const user: UserInfo = ["Alice", 25]; // Ad və yaş

// 3. Object type ilə interface
interface Product {
  name: string;
  price: number;
  inStock?: boolean; // Opsiyonel xüsusiyyət
}
const product: Product = { name: "Laptop", price: 1200 }; // inStock olmadan da işləyir

// 4. Function type: Funksiyanın tipi
type GreetUser = (name: string) => string;
const greet: GreetUser = (name) => `Salam, ${name}!`;

// 5. Union type: Birdən çox tip
type ID = string | number;
let orderId: ID = "A123"; // Və ya rəqəm: 123

// 6. Intersection type: Tiplərin birləşməsi
interface Details {
  category: string;
}
type FullProduct = Product & Details;
const fullProduct: FullProduct = { name: "Mouse", price: 25, category: "Electronics" };

// 7. Literal type: Dəqiq dəyərlər
type OrderStatus = "pending" | "shipped";
let status: OrderStatus = "pending"; // Yalnız bu dəyərlər

// 8. Type alias: Tipə ad vermə
type Item = {
  name: string;
  price: number;
};
const item: Item = { name: "Keyboard", price: 50 };

// Sadə mağaza sistemi
type Status = "pending" | "shipped" | "delivered";
interface Product {
  name: string;
  price: number;
}
interface Order {
  orderId: number;
  status: Status;
  products: Product[];
}

type ShowOrder = (order: Order) => string;
const showOrder: ShowOrder = (order) => {
  return `Sifariş ${order.orderId} (${order.status}): ${order.products.length} məhsul`;
};

const order: Order = {
  orderId: 101,
  status: "pending",
  products: [{ name: "Laptop", price: 1200 }, { name: "Mouse", price: 25 }]
};
console.log(showOrder(order)); // Çıxış: Sifariş 101 (pending): 2 məhsul

