type UserInfo = [string, number];
const user: UserInfo = ["Alice", 25]; // Name and age

// 3. Object type with interface
interface Product {
  name: string;
  price: number;
  inStock?: boolean; // Optional property
}
const product: Product = { name: "Laptop", price: 1200 }; // inStock is optional

// 4. Function type: Function signature
type GreetUser = (name: string) => string;
const greet: GreetUser = (name) => `Hello, ${name}!`;

// 5. Union type: Multiple types
type ID = string | number;
let orderId: ID = "A123"; // Or number: 123

// 6. Intersection type: Combining types
interface Details {
  category: string;
}
type FullProduct = Product & Details;
const fullProduct: FullProduct = { name: "Mouse", price: 25, category: "Electronics" };

// 7. Literal type: Specific values
type OrderStatus = "pending" | "shipped";
let status: OrderStatus = "pending"; // Only these values

// 8. Type alias: Naming types
type Item = {
  name: string;
  price: number;
};
const item: Item = { name: "Keyboard", price: 50 };

// Simple store system
type Status = "pending" | "shipped" | "delivered";
interface Product {
  name: string;
  price: number;
}
interface Order {
  orderId: number;
  status: Status;
  products: Product[];
}

type ShowOrder = (order: Order) => string;
const showOrder: ShowOrder = (order) => {
  return `Order ${order.orderId} (${order.status}): ${order.products.length} items`;
};

const order: Order = {
  orderId: 101,
  status: "pending",
  products: [{ name: "Laptop", price: 1200 }, { name: "Mouse", price: 25 }]
};
console.log(showOrder(order)); // Output: Order 101 (pending): 2 items

