// 1. Базовые типы
let userName: string = "Murad"; // Только строка
let userAge: number = 23; // Только число
let isActive: boolean = true; // Только true/false
// userName = 23; // Ошибка: число не соответствует типу string

// 2. Tuple type: Массив фиксированной длины
type UserInfo = [string, number];
const user: UserInfo = ["Alice", 25]; // Имя и возраст

// 3. Object type с интерфейсом
interface Product {
  name: string;
  price: number;
  inStock?: boolean; // Опциональное свойство
}
const product: Product = { name: "Laptop", price: 1200 }; // inStock необязателен

// 4. Function type: Сигнатура функции
type GreetUser = (name: string) => string;
const greet: GreetUser = (name) => `Привет, ${name}!`;

// 5. Union type: Несколько типов
type ID = string | number;
let orderId: ID = "A123"; // Или число: 123

// 6. Intersection type: Объединение типов
interface Details {
  category: string;
}
type FullProduct = Product & Details;
const fullProduct: FullProduct = { name: "Mouse", price: 25, category: "Electronics" };

// 7. Literal type: Конкретные значения
type OrderStatus = "pending" | "shipped";
let status: OrderStatus = "pending"; // Только эти значения

// 8. Type alias: Именование типов
type Item = {
  name: string;
  price: number;
};
const item: Item = { name: "Keyboard", price: 50 };

// Простая система магазина
type Status = "pending" | "shipped" | "delivered";
interface Product {
  name: string;
  price: number;
}
interface Order {
  orderId: number;
  status: Status;
  products: Product[];
}

type ShowOrder = (order: Order) => string;
const showOrder: ShowOrder = (order) => {
  return `Заказ ${order.orderId} (${order.status}): ${order.products.length} товаров`;
};

const order: Order = {
  orderId: 101,
  status: "pending",
  products: [{ name: "Laptop", price: 1200 }, { name: "Mouse", price: 25 }]
};
console.log(showOrder(order)); // Вывод: Заказ 101 (pending): 2 товаров

